const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function runFulfillWave(t, input) {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), 'harbor-tools-'));
  const inputPath = path.join(directory, 'input.json');
  fs.writeFileSync(inputPath, JSON.stringify(input));
  t.after(() => fs.rmSync(directory, { recursive: true, force: true }));
  return JSON.parse(run(['fulfill-wave', '--input', inputPath]));
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('fulfill-wave accepts an order using FEFO lots from the nearest warehouse', (t) => {
  const output = runFulfillWave(t, {
    warehouses: [
      {
        id: 'far',
        distance: 2,
        lots: [{ sku: 'widget', lot: 'far-lot', qty: 2, expires: '2025-01-01' }],
      },
      {
        id: 'near',
        distance: 1,
        lots: [
          { sku: 'widget', lot: 'late', qty: 4, expires: '2025-03-01' },
          { sku: 'widget', lot: 'early', qty: 2, expires: '2025-02-01' },
        ],
      },
    ],
    orders: [{
      id: 'first',
      priority: 1,
      submitted_at: '2024-01-01T00:00:00Z',
      lines: [{ sku: 'widget', qty: 5, single_warehouse: false }],
    }],
  });

  assert.deepStrictEqual(output, {
    accepted: [{
      id: 'first',
      allocations: [
        { sku: 'widget', warehouse: 'near', lot: 'early', qty: 2 },
        { sku: 'widget', warehouse: 'near', lot: 'late', qty: 3 },
      ],
    }],
    rejected: [],
    remaining: [
      { warehouse: 'far', sku: 'widget', lot: 'far-lot', qty: 2, expires: '2025-01-01' },
      { warehouse: 'near', sku: 'widget', lot: 'late', qty: 1, expires: '2025-03-01' },
    ],
  });
});

test('fulfill-wave restores rejected stock and never combines warehouses for a single-warehouse line', (t) => {
  const output = runFulfillWave(t, {
    warehouses: [
      {
        id: 'a',
        distance: 1,
        lots: [{ sku: 'widget', lot: 'a-lot', qty: 3, expires: '2025-01-01' }],
      },
      {
        id: 'b',
        distance: 2,
        lots: [{ sku: 'widget', lot: 'b-lot', qty: 2, expires: '2025-01-01' }],
      },
    ],
    orders: [
      {
        id: 'rollback',
        priority: 3,
        submitted_at: '2024-01-01T00:00:00Z',
        lines: [
          { sku: 'widget', qty: 1, single_warehouse: false },
          { sku: 'missing', qty: 1, single_warehouse: false },
        ],
      },
      {
        id: 'single',
        priority: 2,
        submitted_at: '2024-01-01T00:00:00Z',
        lines: [{ sku: 'widget', qty: 5, single_warehouse: true }],
      },
      {
        id: 'later',
        priority: 1,
        submitted_at: '2024-01-01T00:00:00Z',
        lines: [{ sku: 'widget', qty: 5, single_warehouse: false }],
      },
    ],
  });

  assert.deepStrictEqual(output, {
    accepted: [{
      id: 'later',
      allocations: [
        { sku: 'widget', warehouse: 'a', lot: 'a-lot', qty: 3 },
        { sku: 'widget', warehouse: 'b', lot: 'b-lot', qty: 2 },
      ],
    }],
    rejected: [
      { id: 'rollback', reason: 'insufficient_stock' },
      { id: 'single', reason: 'insufficient_stock' },
    ],
    remaining: [],
  });
});

