    warehouse.lots.sort(compareLots);
  }

  const accepted = [];
  const rejectedIds = new Set();
  const orders = [...input.orders].sort(compareOrders);

  for (const order of orders) {
    const allocations = [];
    const deductions = [];
    let fulfilled = true;

    for (const line of order.lines) {
      if (line.single_warehouse) {
        const warehouse = warehouses.find((candidate) => candidate.lots
          .filter((lot) => lot.sku === line.sku)
          .reduce((total, lot) => total + lot.qty, 0) >= line.qty);
        fulfilled = Boolean(warehouse)
          && consumeFromWarehouse(warehouse, line, allocations, deductions);
      } else {
        let needed = line.qty;
        for (const warehouse of warehouses) {
          const before = allocations.length;
          consumeFromWarehouse(warehouse, { ...line, qty: needed }, allocations, deductions);
          needed -= allocations.slice(before).reduce((total, allocation) => total + allocation.qty, 0);
          if (needed === 0) break;
        }
        fulfilled = needed === 0;
      }

      if (!fulfilled) break;
    }

    if (fulfilled) {
      accepted.push({ id: order.id, allocations });
      continue;
    }

    for (const deduction of deductions) {
      deduction.lot.qty += deduction.qty;
    }
    rejectedIds.add(order.id);
  }

  const rejected = input.orders
    .filter((order) => rejectedIds.has(order.id))
    .map((order) => ({ id: order.id, reason: 'insufficient_stock' }));
  const remaining = warehouses.flatMap((warehouse) => warehouse.lots
    .filter((lot) => lot.qty > 0)
    .map((lot) => ({
      warehouse: warehouse.id,
      sku: lot.sku,
      lot: lot.lot,
      qty: lot.qty,
      expires: lot.expires,
    })))
    .sort((left, right) => left.warehouse.localeCompare(right.warehouse)
      || left.sku.localeCompare(right.sku)
      || left.expires.localeCompare(right.expires)
      || left.lot.localeCompare(right.lot));

  return { accepted, rejected, remaining };
}

function fulfillWave(argv) {
  try {
    const index = argv.indexOf('--input');
    const inputPath = argv[index + 1];
    if (index === -1 || !inputPath || inputPath.startsWith('-')) {
      throw new Error('--input requires a path');
    }

    const input = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
    validateInput(input);
    const result = allocateWave(JSON.parse(JSON.stringify(input)));
    process.stdout.write(`${JSON.stringify(result)}\n`);
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    process.stderr.write(`${JSON.stringify({ error: message })}\n`);
    process.exitCode = 2;
  }
}

function main(argv) {
  const [command, ...rest] = argv;

  if (!command || command === '--help' || command === '-h') {
    process.stdout.write(USAGE);
    return;
  }

  switch (command) {
    case 'hello': {
      const name = parseNameFlag(rest);
      console.log(`Hello, ${name}!`);
      return;
    }
    case 'version': {
      console.log(readPackageVersion());
      return;
    }
    case 'fulfill-wave': {
      fulfillWave(rest);
      return;
    }
    default:
      console.error(`Unknown command: ${command}`);
      process.stderr.write(USAGE);
      process.exit(1);
  }
}

main(process.argv.slice(2));

